INSERT INTO solarnet.sn_metric_campaign_optin (
	campaign_id
	, node_id
	, source_id
	, prop_type
	, prop_name
	, created
) VALUES (
	#{campaignId}
	, #{nodeId}
	, #{sourceId}
	, #{propertyTypeKey}
	, #{propertyName}
	, #{created}
)
ON CONFLICT (campaign_id, node_id, source_id, prop_type, prop_name) DO NOTHING

