SELECT

FROM
	solarnet.sn_metric_campaign_optin mco
WHERE
	mco.campaign_id = #{campaignId}
	AND mco.node_id = #{nodeId}
	AND mco.source_id = #{sourceId}
	AND mco.prop_type = #{propertyTypeKey}
